SELECT COUNT(DISTINCT LP.PK) AS TOTAL FROM LATTES_PRODTEC LP JOIN LATTES_P_PRODTEC LPP ON LP.PK = LPP.FK_PRODTEC JOIN SERVIDOR S ON LPP.FK_SIAPE = S.PK_SIAPE WHERE LP.ANO = 2022 AND LOWER(LP.NATUREZA) LIKE LOWER('%consultoria%') AND LOWER(S.GENERO) = LOWER('masculino') AND (LOWER(S.SIGLA_CAMPUS) = LOWER('jat') OR LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%jatai%') OR LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%jatai%')) AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%matemat%')